1980 static bool matchConstantMaskBitfieldClear(Value *OldBits, Value *NewBits,
1981                                            Value *&X, Value *&NotYAndM) {
1982   const APInt *Mask, *NotMask, *YMask;
1983 
1984   if (!match(OldBits, m_c_And(m_Value(X), m_APInt(NotMask))))
1985     return false;
1986 
1987   if (!match(NewBits,
1988              m_c_And(
1989                  m_c_And(m_Specific(X), m_APInt(Mask)),
1990                  m_Value(NotYAndM, m_Not(m_c_And(m_Value(), m_APInt(YMask)))))))
1991     return false;
1992 
1993   return *Mask == *YMask && *NotMask == ~*Mask;
1994 }
