1996 static Instruction *foldOrOfConstantMaskBitfieldClear(BinaryOperator &I) {
1997   assert(I.getOpcode() == Instruction::Or);
1998 
1999   if (!I.getType()->isIntegerTy())
2000     return nullptr;
2001 
2002   // (X & ~M) | ((X & M) & ~(Y & M)) --> X & ~(Y & M)
2003   // Match only the exact constant-mask shape. The replacement reuses the
2004   // existing complement of (Y & M), so multi-use operands are not duplicated.
2005   Value *X, *NotYAndM;
2006   if (matchConstantMaskBitfieldClear(I.getOperand(0), I.getOperand(1), X,
2007                                      NotYAndM) ||
2008       matchConstantMaskBitfieldClear(I.getOperand(1), I.getOperand(0), X,
2009                                      NotYAndM))
2010     return BinaryOperator::CreateAnd(X, NotYAndM);
2011 
2012   return nullptr;
2013 }
