2017 static bool canNarrowShiftAmt(Constant *C, unsigned BitWidth) {
2018   APInt Threshold(C->getType()->getScalarSizeInBits(), BitWidth);
2019   return match(C, m_SpecificInt_ICMP(ICmpInst::ICMP_ULT, Threshold));
