2022 /// Try to use narrower ops (sink zext ops) for an 'and' with binop operand and
2023 /// a common zext operand: and (binop (zext X), C), (zext X).
2024 Instruction *InstCombinerImpl::narrowMaskedBinOp(BinaryOperator &And) {
2025   // This transform could also apply to {or, and, xor}, but there are better
2026   // folds for those cases, so we don't expect those patterns here. AShr is not
2027   // handled because it should always be transformed to LShr in this sequence.
2028   // The subtract transform is different because it has a constant on the left.
2029   // Add/mul commute the constant to RHS; sub with constant RHS becomes add.
2030   Value *Op0 = And.getOperand(0), *Op1 = And.getOperand(1);
2031   Constant *C;
2032   if (!match(Op0, m_OneUse(m_Add(m_Specific(Op1), m_Constant(C)))) &&
2033       !match(Op0, m_OneUse(m_Mul(m_Specific(Op1), m_Constant(C)))) &&
2034       !match(Op0, m_OneUse(m_LShr(m_Specific(Op1), m_Constant(C)))) &&
2035       !match(Op0, m_OneUse(m_Shl(m_Specific(Op1), m_Constant(C)))) &&
2036       !match(Op0, m_OneUse(m_Sub(m_Constant(C), m_Specific(Op1)))))
2037     return nullptr;
2038 
2039   Value *X;
2040   if (!match(Op1, m_ZExt(m_Value(X))) || Op1->hasNUsesOrMore(3))
2041     return nullptr;
2042 
2043   Type *Ty = And.getType();
2044   if (!isa<VectorType>(Ty) && !shouldChangeType(Ty, X->getType()))
2045     return nullptr;
2046 
2047   // If we're narrowing a shift, the shift amount must be safe (less than the
2048   // width) in the narrower type. If the shift amount is greater, instsimplify
2049   // usually handles that case, but we can't guarantee/assert it.
2050   Instruction::BinaryOps Opc = cast<BinaryOperator>(Op0)->getOpcode();
2051   if (Opc == Instruction::LShr || Opc == Instruction::Shl)
2052     if (!canNarrowShiftAmt(C, X->getType()->getScalarSizeInBits()))
2053       return nullptr;
2054 
2055   // and (sub C, (zext X)), (zext X) --> zext (and (sub C', X), X)
2056   // and (binop (zext X), C), (zext X) --> zext (and (binop X, C'), X)
2057   Value *NewC = ConstantExpr::getTrunc(C, X->getType());
2058   Value *NewBO = Opc == Instruction::Sub ? Builder.CreateBinOp(Opc, NewC, X)
2059                                          : Builder.CreateBinOp(Opc, X, NewC);
2060   return new ZExtInst(Builder.CreateAnd(NewBO, X), Ty);
2061 }
